 /// Replace a select operand based on an equality comparison with the identity
+SkipSelectIntoFMul: ;
 /// constant of a binop.
+SkipSelectIntoFMul: ;
 static Instruction *foldSelectBinOpIdentity(SelectInst &Sel,
+SkipSelectIntoFMul: ;
                                             const TargetLibraryInfo &TLI,
+SkipSelectIntoFMul: ;
                                             InstCombinerImpl &IC) {
+SkipSelectIntoFMul: ;
   // The select condition must be an equality compare with a constant operand.
+SkipSelectIntoFMul: ;
   Value *X;
+SkipSelectIntoFMul: ;
   Constant *C;
+SkipSelectIntoFMul: ;
   CmpInst::Predicate Pred;
+SkipSelectIntoFMul: ;
   if (!match(Sel.getCondition(), m_Cmp(Pred, m_Value(X), m_Constant(C))))
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   bool IsEq;
+SkipSelectIntoFMul: ;
   if (ICmpInst::isEquality(Pred))
+SkipSelectIntoFMul: ;
     IsEq = Pred == ICmpInst::ICMP_EQ;
+SkipSelectIntoFMul: ;
   else if (Pred == FCmpInst::FCMP_OEQ)
+SkipSelectIntoFMul: ;
     IsEq = true;
+SkipSelectIntoFMul: ;
   else if (Pred == FCmpInst::FCMP_UNE)
+SkipSelectIntoFMul: ;
     IsEq = false;
+SkipSelectIntoFMul: ;
   else
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // A select operand must be a binop.
+SkipSelectIntoFMul: ;
   BinaryOperator *BO;
+SkipSelectIntoFMul: ;
   if (!match(Sel.getOperand(IsEq ? 1 : 2), m_BinOp(BO)))
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // The compare constant must be the identity constant for that binop.
+SkipSelectIntoFMul: ;
   // If this a floating-point compare with 0.0, any zero constant will do.
+SkipSelectIntoFMul: ;
   Type *Ty = BO->getType();
+SkipSelectIntoFMul: ;
   Constant *IdC = ConstantExpr::getBinOpIdentity(BO->getOpcode(), Ty, true);
+SkipSelectIntoFMul: ;
   if (IdC != C) {
+SkipSelectIntoFMul: ;
     if (!IdC || !CmpInst::isFPPredicate(Pred))
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;
     if (!match(IdC, m_AnyZeroFP()) || !match(C, m_AnyZeroFP()))
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;
   }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // Last, match the compare variable operand with a binop operand.
+SkipSelectIntoFMul: ;
   Value *Y;
+SkipSelectIntoFMul: ;
   if (!BO->isCommutative() && !match(BO, m_BinOp(m_Value(Y), m_Specific(X))))
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;
   if (!match(BO, m_c_BinOp(m_Value(Y), m_Specific(X))))
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // +0.0 compares equal to -0.0, and so it does not behave as required for this
+SkipSelectIntoFMul: ;
   // transform. Bail out if we can not exclude that possibility.
+SkipSelectIntoFMul: ;
   if (isa<FPMathOperator>(BO))
+SkipSelectIntoFMul: ;
     if (!BO->hasNoSignedZeros() &&
+SkipSelectIntoFMul: ;
         !cannotBeNegativeZero(Y, 0,
+SkipSelectIntoFMul: ;
                               IC.getSimplifyQuery().getWithInstruction(&Sel)))
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // BO = binop Y, X
+SkipSelectIntoFMul: ;
   // S = { select (cmp eq X, C), BO, ? } or { select (cmp ne X, C), ?, BO }
+SkipSelectIntoFMul: ;
   // =>
+SkipSelectIntoFMul: ;
   // S = { select (cmp eq X, C),  Y, ? } or { select (cmp ne X, C), ?,  Y }
+SkipSelectIntoFMul: ;
   return IC.replaceOperand(Sel, IsEq ? 1 : 2, Y);
+SkipSelectIntoFMul: ;
 }
