 /// This folds:
+SkipSelectIntoFMul: ;
 ///  select (icmp eq (and X, C1)), TC, FC
+SkipSelectIntoFMul: ;
 ///    iff C1 is a power 2 and the difference between TC and FC is a power-of-2.
+SkipSelectIntoFMul: ;
 /// To something like:
+SkipSelectIntoFMul: ;
 ///  (shr (and (X, C1)), (log2(C1) - log2(TC-FC))) + FC
+SkipSelectIntoFMul: ;
 /// Or:
+SkipSelectIntoFMul: ;
 ///  (shl (and (X, C1)), (log2(TC-FC) - log2(C1))) + FC
+SkipSelectIntoFMul: ;
 /// With some variations depending if FC is larger than TC, or the shift
+SkipSelectIntoFMul: ;
 /// isn't needed, or the bit widths don't match.
+SkipSelectIntoFMul: ;
 static Value *foldSelectICmpAnd(SelectInst &Sel, ICmpInst *Cmp,
+SkipSelectIntoFMul: ;
                                 InstCombiner::BuilderTy &Builder) {
+SkipSelectIntoFMul: ;
   const APInt *SelTC, *SelFC;
+SkipSelectIntoFMul: ;
   if (!match(Sel.getTrueValue(), m_APInt(SelTC)) ||
+SkipSelectIntoFMul: ;
       !match(Sel.getFalseValue(), m_APInt(SelFC)))
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // If this is a vector select, we need a vector compare.
+SkipSelectIntoFMul: ;
   Type *SelType = Sel.getType();
+SkipSelectIntoFMul: ;
   if (SelType->isVectorTy() != Cmp->getType()->isVectorTy())
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   Value *V;
+SkipSelectIntoFMul: ;
   APInt AndMask;
+SkipSelectIntoFMul: ;
   bool CreateAnd = false;
+SkipSelectIntoFMul: ;
   ICmpInst::Predicate Pred = Cmp->getPredicate();
+SkipSelectIntoFMul: ;
   if (ICmpInst::isEquality(Pred)) {
+SkipSelectIntoFMul: ;
     if (!match(Cmp->getOperand(1), m_Zero()))
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
     V = Cmp->getOperand(0);
+SkipSelectIntoFMul: ;
     const APInt *AndRHS;
+SkipSelectIntoFMul: ;
     if (!match(V, m_And(m_Value(), m_Power2(AndRHS))))
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
     AndMask = *AndRHS;
+SkipSelectIntoFMul: ;
   } else if (auto Res = decomposeBitTestICmp(Cmp->getOperand(0),
+SkipSelectIntoFMul: ;
                                              Cmp->getOperand(1), Pred)) {
+SkipSelectIntoFMul: ;
     assert(ICmpInst::isEquality(Res->Pred) && "Not equality test?");
+SkipSelectIntoFMul: ;
     if (!Res->Mask.isPowerOf2())
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
     V = Res->X;
+SkipSelectIntoFMul: ;
     AndMask = Res->Mask;
+SkipSelectIntoFMul: ;
     Pred = Res->Pred;
+SkipSelectIntoFMul: ;
     CreateAnd = true;
+SkipSelectIntoFMul: ;
   } else {
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;
   }
+SkipSelectIntoFMul: ;
   if (Pred == ICmpInst::ICMP_NE)
+SkipSelectIntoFMul: ;
     std::swap(SelTC, SelFC);
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // In general, when both constants are non-zero, we would need an offset to
+SkipSelectIntoFMul: ;
   // replace the select. This would require more instructions than we started
+SkipSelectIntoFMul: ;
   // with. But there's one special-case that we handle here because it can
+SkipSelectIntoFMul: ;
   // simplify/reduce the instructions.
+SkipSelectIntoFMul: ;
   const APInt &TC = *SelTC;
+SkipSelectIntoFMul: ;
   const APInt &FC = *SelFC;
+SkipSelectIntoFMul: ;
   if (!TC.isZero() && !FC.isZero()) {
+SkipSelectIntoFMul: ;
     if (TC.getBitWidth() != AndMask.getBitWidth())
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;
     // If we have to create an 'and', then we must kill the cmp to not
+SkipSelectIntoFMul: ;
     // increase the instruction count.
+SkipSelectIntoFMul: ;
     if (CreateAnd && !Cmp->hasOneUse())
+SkipSelectIntoFMul: ;
       return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
     // (V & AndMaskC) == 0 ? TC : FC --> TC | (V & AndMaskC)
+SkipSelectIntoFMul: ;
     // (V & AndMaskC) == 0 ? TC : FC --> TC ^ (V & AndMaskC)
+SkipSelectIntoFMul: ;
     // (V & AndMaskC) == 0 ? TC : FC --> TC + (V & AndMaskC)
+SkipSelectIntoFMul: ;
     // (V & AndMaskC) == 0 ? TC : FC --> TC - (V & AndMaskC)
+SkipSelectIntoFMul: ;
     Constant *TCC = ConstantInt::get(SelType, TC);
+SkipSelectIntoFMul: ;
     Constant *FCC = ConstantInt::get(SelType, FC);
+SkipSelectIntoFMul: ;
     Constant *MaskC = ConstantInt::get(SelType, AndMask);
+SkipSelectIntoFMul: ;
     for (auto Opc : {Instruction::Or, Instruction::Xor, Instruction::Add,
+SkipSelectIntoFMul: ;
                      Instruction::Sub}) {
+SkipSelectIntoFMul: ;
       if (ConstantFoldBinaryOpOperands(Opc, TCC, MaskC, Sel.getDataLayout()) ==
+SkipSelectIntoFMul: ;
           FCC) {
+SkipSelectIntoFMul: ;
         if (CreateAnd)
+SkipSelectIntoFMul: ;
           V = Builder.CreateAnd(V, MaskC);
+SkipSelectIntoFMul: ;
         return Builder.CreateBinOp(Opc, TCC, V);
+SkipSelectIntoFMul: ;
       }
+SkipSelectIntoFMul: ;
     }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;
   }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // Make sure one of the select arms is a power-of-2.
+SkipSelectIntoFMul: ;
   if (!TC.isPowerOf2() && !FC.isPowerOf2())
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // Determine which shift is needed to transform result of the 'and' into the
+SkipSelectIntoFMul: ;
   // desired result.
+SkipSelectIntoFMul: ;
   const APInt &ValC = !TC.isZero() ? TC : FC;
+SkipSelectIntoFMul: ;
   unsigned ValZeros = ValC.logBase2();
+SkipSelectIntoFMul: ;
   unsigned AndZeros = AndMask.logBase2();
+SkipSelectIntoFMul: ;
   bool ShouldNotVal = !TC.isZero();
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // If we would need to create an 'and' + 'shift' + 'xor' to replace a 'select'
+SkipSelectIntoFMul: ;
   // + 'icmp', then this transformation would result in more instructions and
+SkipSelectIntoFMul: ;
   // potentially interfere with other folding.
+SkipSelectIntoFMul: ;
   if (CreateAnd && ShouldNotVal && ValZeros != AndZeros)
+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // Insert the 'and' instruction on the input to the truncate.
+SkipSelectIntoFMul: ;
   if (CreateAnd)
+SkipSelectIntoFMul: ;
     V = Builder.CreateAnd(V, ConstantInt::get(V->getType(), AndMask));
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // If types don't match, we can still convert the select by introducing a zext
+SkipSelectIntoFMul: ;
   // or a trunc of the 'and'.
+SkipSelectIntoFMul: ;
   if (ValZeros > AndZeros) {
+SkipSelectIntoFMul: ;
