+SkipSelectIntoFMul: ;
   switch (I->getOpcode()) {
+SkipSelectIntoFMul: ;
   case Instruction::Add:
+SkipSelectIntoFMul: ;
   case Instruction::FAdd:
+SkipSelectIntoFMul: ;
   case Instruction::Mul:
+SkipSelectIntoFMul: ;
   case Instruction::FMul:
+SkipSelectIntoFMul: ;
   case Instruction::And:
+SkipSelectIntoFMul: ;
