+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   if (Instruction *I = foldBitCeil(SI, Builder))
+SkipSelectIntoFMul: ;
     return I;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   if (Instruction *I = foldSelectToCmp(SI))
+SkipSelectIntoFMul: ;
     return I;
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
