+SkipSelectIntoFMul: ;
           return SelectInst::Create(A, IsAnd ? V : TrueVal,
+SkipSelectIntoFMul: ;
                                     IsAnd ? FalseVal : V);
+SkipSelectIntoFMul: ;
     }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
     return nullptr;
+SkipSelectIntoFMul: ;
   };
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   Value *LHS, *RHS;
+SkipSelectIntoFMul: ;
