+SkipSelectIntoFMul: ;
         return I;
+SkipSelectIntoFMul: ;
     }
+SkipSelectIntoFMul: ;
   }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // select Cond, !X, X -> xor Cond, X
+SkipSelectIntoFMul: ;
