+SkipSelectIntoFMul: ;
                                 ConstantInt::get(SelType, Known.getConstant()));
+SkipSelectIntoFMul: ;
       }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
       CC.Invert = true;
+SkipSelectIntoFMul: ;
       if (!isa<Constant>(FalseVal) &&
+SkipSelectIntoFMul: ;
           hasAffectedValue(FalseVal, CC.AffectedValues, /*Depth=*/0)) {
+SkipSelectIntoFMul: ;
         KnownBits Known = llvm::computeKnownBits(FalseVal, /*Depth=*/0, Q);
+SkipSelectIntoFMul: ;
         if (Known.isConstant())
+SkipSelectIntoFMul: ;
           return replaceOperand(SI, 2,
+SkipSelectIntoFMul: ;
                                 ConstantInt::get(SelType, Known.getConstant()));
+SkipSelectIntoFMul: ;
       }
+SkipSelectIntoFMul: ;
     }
+SkipSelectIntoFMul: ;
   }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   // select (trunc nuw X to i1), X, Y --> select (trunc nuw X to i1), 1, Y
+SkipSelectIntoFMul: ;
   // select (trunc nuw X to i1), Y, X --> select (trunc nuw X to i1), Y, 0
+SkipSelectIntoFMul: ;
   // select (trunc nsw X to i1), X, Y --> select (trunc nsw X to i1), -1, Y
+SkipSelectIntoFMul: ;
   // select (trunc nsw X to i1), Y, X --> select (trunc nsw X to i1), Y, 0
+SkipSelectIntoFMul: ;
   Value *Trunc;
+SkipSelectIntoFMul: ;
   if (match(CondVal, m_NUWTrunc(m_Value(Trunc)))) {
+SkipSelectIntoFMul: ;
     if (TrueVal == Trunc)
+SkipSelectIntoFMul: ;
       return replaceOperand(SI, 1, ConstantInt::get(TrueVal->getType(), 1));
+SkipSelectIntoFMul: ;
     if (FalseVal == Trunc)
+SkipSelectIntoFMul: ;
       return replaceOperand(SI, 2, ConstantInt::get(FalseVal->getType(), 0));
+SkipSelectIntoFMul: ;
   }
+SkipSelectIntoFMul: ;
   if (match(CondVal, m_NSWTrunc(m_Value(Trunc)))) {
+SkipSelectIntoFMul: ;
     if (TrueVal == Trunc)
+SkipSelectIntoFMul: ;
       return replaceOperand(SI, 1,
+SkipSelectIntoFMul: ;
                             Constant::getAllOnesValue(TrueVal->getType()));
+SkipSelectIntoFMul: ;
     if (FalseVal == Trunc)
+SkipSelectIntoFMul: ;
       return replaceOperand(SI, 2, ConstantInt::get(FalseVal->getType(), 0));
+SkipSelectIntoFMul: ;
   }
+SkipSelectIntoFMul: ;

+SkipSelectIntoFMul: ;
   return nullptr;
+SkipSelectIntoFMul: ;
 }
